\begin{definition}
\label{def:0.1}
Let $\mathcal{M}^N$ denote the space of $N \times N$ complex matrices, let $\mathcal{P}_M$ denote the space of polynomials with complex coefficients and degree $\leq M$, and let $\|\cdot\|$ denote the vector or matrix 2-norm. The field of values (or numerical range) of $A \in \mathcal{M}^N$ is
\[
\label{eq:0.u1}
W(A)=\{v^*Av\ :\ v \in \mathbb{C}^N,\ \|v\|=1\},
\]
and
\[
\label{eq:0.u2}
\|p\|_{W(A)}=\max_{\zeta\in W(A)}|p(\zeta)|=\max_{\|v\|=1}|p(v^*Av)|.
\]
\end{definition}

\begin{proposition}
\label{prop:0.1}
\textbf{Proposition 1.}

Let $\nu:E\to \mathbb{R}$ be locally Lipschitz, directionally differentiable and regular on an open set $X\in E$ and let $\delta:E\to \mathbb{R}$ be smooth on $X$ with gradient $\nabla\delta$. Define the quotient $h$ by $x\mapsto \nu(x)/\delta(x)$, assuming $\delta(x)\neq 0$ for $x\in X$. Then $h$ is regular on $X$ with subdifferential

\[
\label{eq:0.u3}
\partial h(x)=\frac{\delta(x)\partial \nu(x)-\nu(x)\nabla \delta(x)}{\delta(x)^2}.
\]
\end{proposition}

\begin{proposition}
\label{prop:0.2}
\textbf{Proposition 2.} For $\theta\in [0,2\pi)$, define the Hermitian matrix
\[
\label{eq:0.u4}
H_\theta=\frac{1}{2}\left(e^{i\theta}A+e^{-i\theta}A^*\right).
\qquad (4)
\]
A point $z$ is a boundary point of $W(A)$ if and only if $z=v^*Av$ where $v$ is a unit eigenvector of $H_\theta$ corresponding to $\lambda_{\max}(H_\theta)$, the largest eigenvalue of $H_\theta$, for some $\theta \in [0, 2\pi)$.
\end{proposition}

\begin{definition}
\label{def:0.2}
Let us identify $p \in \mathcal{P}_M$ with its coefficient vector $c=[c_0,c_1,\ldots,c_M]^T \in \mathbb{C}^{M+1}$, with $c_j \neq 0$ for at least one $j \in \{1,\ldots,M\}$, and define the function $q:\mathbb{C}^{M+1}\times \mathbb{C}\rightarrow \mathbb{C}$ by
\[
\label{eq:0.u5}
q(c,\zeta)=\sum_{j=0}^M c_j \zeta^j.
\]
Depending on the context, we will also interpret $q$ as a function mapping $\mathbb{C}^{M+1}\times \mathcal{M}^N$ to $\mathcal{M}^N$, defined by substituting $A \in \mathcal{M}^N$ for $\zeta \in \mathbb{C}$ above.
\end{definition}

\begin{definition}
\label{def:0.3}
We write the Crouzeix ratio as
\[
\label{eq:0.u6}
f(c,A)=\frac{\tau(c,A)}{\beta(c,A)}
\]
where
\[
\tau(c,A)=\max\{|q(c,z)|:z \in W(A)\},
\tag{5}\label{eq:5}
\]
and
\[
\beta(c,A)=\|p(A)\|=\sigma_{\max}(q(c,A)),
\tag{6}\label{eq:6}
\]
the largest singular value of $\sum_{j=0}^M c_jA^j$.
\end{definition}

\begin{definition}
\label{def:0.4}
We can rewrite $\tau$ as
\[
\tau(c,A)=\max\{\phi(c,A,\omega,v):|\omega|=1,\ \|v\|=1\},
\tag{7}\label{eq:7}
\]
where the function $\phi:\mathbb{C}^{M+1}\times\mathcal{M}^N\times\mathbb{C}\times\mathbb{C}^N\to\mathbb{R}$ is defined by
\[
\label{eq:0.u7}
\phi(c,A,\omega,v)=\operatorname{Re}(\omega^*q(c,v^*Av)).
\]
Let $Z(c,A)$ denote the set of points $z\in W(A)$ attaining the maximum \eqref{eq:5} and let $\Omega(c,A)$ denote the set of pairs $(\omega,v)$ attaining the maximum in (7). Clearly
\[
\label{eq:0.u8}
\Omega(c,A)=\{(\omega,v):|\omega|=1,\ \|v\|=1,\ z\in Z(c,A),\ v^*Av=z,\ \omega^*z=|q(c,z)|\}.
\]
\end{definition}

\begin{theorem}
\label{thm:0.1}
\[
\partial f(c,A)=\frac{\beta(c,A)\partial\tau(c,A)-\tau(c,A)\nabla\beta(c,A)}{\beta(c,A)^2},
\tag{11}\label{eq:11}
\]
where $\partial\tau(c,A)$ and $\nabla\beta(c,A)$ are given by (9) and (10) respectively.
\end{theorem}

\begin{theorem}
\label{thm:0.2}
Let $c$, $A$ be given by (12), (13). The subdifferential of the Crouzeix ratio at $(c,A)$ is

\[
\partial f(c,A)=\operatorname{conv}_{\theta\in[0,2\pi]}\left\{(y_\theta,Y_\theta)\right\}
\tag{14}\label{eq:14}
\]

where

\[
y_\theta=\frac{1}{2}\left[z^m,z^{m-1},\ldots,z,0,z^{-1},z^{-2},\ldots,z^{m-M}\right]^T
\tag{15}\label{eq:15}
\]

and $Y_\theta$ is the block diagonal matrix $\operatorname{diag}(\tilde{Y}_\theta,0)$, where $\tilde{Y}_\theta$ is the $n\times n$ matrix

\[
\tilde{Y}_\theta=\frac{1}{4}\begin{bmatrix}
z & 0 & \sqrt{2}z^{-1} & \sqrt{2}z^{-2} & \cdots & \sqrt{2}z^{3-n} & z^{2-n}\\
\sqrt{2}z^2 & 2z & 0 & 2z^{-1} & \cdots & 2z^{4-n} & \sqrt{2}z^{3-n}\\
\vdots & & & & & & \vdots\\
\sqrt{2}z^{n-2} & 2z^{n-3} & 2z^{n-4} & 2z^{n-5} & \cdots & 0 & \sqrt{2}z\\
\sqrt{2}z^{n-1} & 2z^{n-2} & 2z^{n-3} & 2z^{n-4} & \cdots & 2z & 0\\
z^n & \sqrt{2}z^{n-1} & \sqrt{2}z^{n-2} & \sqrt{2}z^{n-3} & \cdots & \sqrt{2}z^2 & z
\end{bmatrix}
\tag{16}\label{eq:16}
\]

with $z=e^{-i\theta}$. When $n=2$, these should be interpreted as

\[
y_\theta=[z,0,z^{-1},\ldots,z^{1-M}]^T \quad \text{and} \quad \tilde{Y}_\theta=\frac{1}{4}\begin{bmatrix} z & 0 \\ z^2 & z \end{bmatrix}.
\tag{17}\label{eq:17}
\]
\end{theorem}

\begin{proposition}
\label{prop:0.3}
Fix $M=m=1$ and $p$ by $p(\zeta)=\zeta$, equivalently $c=[0,1]^T$, and write
\[
\label{eq:0.u9}
\check f(A)=f(c,A)=\frac{\check\tau(A)}{\check\beta(A)}=\frac{\tau(c,A)}{\beta(c,A)}.
\]
Let $N=n=3$ and fix $A$ to be given by $\hat A$ in (2), that is, a $3\times 3$ Jordan block with zero on the diagonal, scaled by $\sqrt{2}$. Then $W(A)$ is the unit disk $\mathcal{D}$, so the numerator $\check\tau(A)=1$, but the denominator $\check\beta(A)=\sqrt{2}$. So, $\check f(A)=1/\sqrt{2}$. Now, let $D=A^2=2e_1e_3^*$. Then $\tilde{f}'(A;D)=\frac{\frac{\sqrt{2}}{2}-1}{2}<0$, and a similar argument shows that $\tilde{f}'(A;-D)=\tilde{f}'(A;D)<0$. Hence, the directional derivative $\tilde{f}'(A;\cdot)$ is not sublinear, and it follows from the discussion in Sect.~2 that $\tilde{f}$ is not regular at $A$, and so $f$ is not regular at $(c,A)$.
\end{proposition}

\begin{theorem}
\label{thm:0.3}
gives conditions under which the ratio $f$ is (Clarke) regular, and Theorem 4confirms that $f$ is regular at $(c,A)$ given by (12) and (13). However, under the same conditions, it follows from the representation (7) of the numerator and the smoothness of the denominator that the ratio has the stronger property of prox-regularity at $(c,A)$. Indeed, it can be written locally as the sum of a continuous convex function and a $C^2$ smooth function [19, Thm. 10.33].
\end{theorem}
